            REQUEST_DENIED: "\u0e17\u0e48\u0e32\u0e19\u0e16\u0e39\u0e01\u0e1a\u0e25\u0e47\u0e2d\u0e04\u0e08\u0e32\u0e01\u0e01\u0e32\u0e23\u0e40\u0e25\u0e48\u0e19\u0e40\u0e01\u0e21\u0e19\u0e35\u0e49 \n\u0e01\u0e23\u0e38\u0e13\u0e32\u0e15\u0e34\u0e14\u0e15\u0e48\u0e2d\u0e41\u0e2d\u0e14\u0e21\u0e34\u0e19!",
            ERROR_CONNECTION_HISTORY: "\u0e40\u0e01\u0e34\u0e14\u0e02\u0e49\u0e2d\u0e1c\u0e34\u0e14\u0e1e\u0e25\u0e32\u0e14\u0e43\u0e19\u0e01\u0e32\u0e23\u0e40\u0e0a\u0e37\u0e48\u0e2d\u0e21\u0e15\u0e48\u0e2d\n\u0e01\u0e23\u0e38\u0e13\u0e32\u0e25\u0e2d\u0e07\u0e43\u0e2b\u0e21\u0e48\u0e2d\u0e35\u0e01\u0e04\u0e23\u0e31\u0e49\u0e07\u0e43\u0e19\u0e20\u0e32\u0e22\u0e2b\u0e25\u0e31\u0e07",
            PROMOTION_MESSAGE: "\u0e04\u0e38\u0e13\u0e44\u0e14\u0e49\u0e23\u0e31\u0e1a\u0e2b\u0e21\u0e38\u0e19\u0e1f\u0e23\u0e35 {1} \u0e23\u0e2d\u0e1a \n\u0e14\u0e49\u0e27\u0e22\u0e40\u0e14\u0e34\u0e21\u0e1e\u0e31\u0e19\u0e23\u0e27\u0e21: {2}",
            PROMOTION_RESET: "\u0e02\u0e2d\u0e07\u0e02\u0e27\u0e31\u0e0d: \u0e2b\u0e21\u0e38\u0e19\u0e1f\u0e23\u0e35 {1} \u0e23\u0e2d\u0e1a \n\u0e43\u0e19\u0e27\u0e31\u0e19\u0e43\u0e2b\u0e21\u0e48 (\u0e40\u0e14\u0e34\u0e21\u0e1e\u0e31\u0e19\u0e23\u0e27\u0e21: {2}) \n\u0e2b\u0e21\u0e38\u0e19\u0e15\u0e48\u0e2d\u0e44\u0e1b!",
            PROMOTION_NEW: "\u0e02\u0e2d\u0e07\u0e02\u0e27\u0e31\u0e0d: \u0e2b\u0e21\u0e38\u0e19\u0e1f\u0e23\u0e35 {1} \u0e23\u0e2d\u0e1a \n(\u0e40\u0e14\u0e34\u0e21\u0e1e\u0e31\u0e19\u0e23\u0e27\u0e21: {2}) \u0e2b\u0e21\u0e38\u0e19\u0e15\u0e48\u0e2d\u0e44\u0e1b!",
            FREEGAME_REMAIN: "\u0e04\u0e38\u0e13\u0e40\u0e2b\u0e25\u0e37\u0e2d\u0e2b\u0e21\u0e38\u0e19\u0e1f\u0e23\u0e35 {1} \u0e23\u0e2d\u0e1a",
            ACCOUNT_BLOCKED: "\u0e1a\u0e31\u0e0d\u0e0a\u0e35\u0e02\u0e2d\u0e07\u0e04\u0e38\u0e13\u0e16\u0e39\u0e01\u0e25\u0e47\u0e2d\u0e04 \n\u0e42\u0e1b\u0e23\u0e14\u0e15\u0e34\u0e14\u0e15\u0e48\u0e2d\u0e41\u0e2d\u0e14\u0e21\u0e34\u0e19",
            ACCOUNT_BLOCKED_IFRAME: "\u0e1a\u0e31\u0e0d\u0e0a\u0e35\u0e16\u0e39\u0e01\u0e25\u0e47\u0e2d\u0e04\u0e08\u0e32\u0e01\u0e01\u0e32\u0e23\u0e40\u0e25\u0e48\u0e19\u0e40\u0e01\u0e21 \n{1}",
            SELECT_SPINTIME: "\u0e08\u0e33\u0e19\u0e27\u0e19\u0e01\u0e32\u0e23\u0e2b\u0e21\u0e38\u0e19\u0e2d\u0e31\u0e15\u0e42\u0e19\u0e21\u0e31\u0e15\u0e34",
            START_AUTO_SPIN: "\u0e40\u0e23\u0e34\u0e48\u0e21\u0e40\u0e25\u0e22",
            BUY_CONFIRM: "\u0e04\u0e38\u0e13\u0e22\u0e37\u0e19\u0e22\u0e31\u0e19\u0e17\u0e35\u0e48\u0e08\u0e30\u0e0b\u0e37\u0e49\u0e2d {1} \u0e14\u0e49\u0e27\u0e22\u0e23\u0e32\u0e04\u0e32 {2} \u0e2b\u0e23\u0e37\u0e2d\u0e44\u0e21\u0e48",
            EVENT_FORCE_CLOSE: "\u0e1b\u0e34\u0e14\u0e01\u0e34\u0e08\u0e01\u0e23\u0e23\u0e21",
